    directionalAxis: "x" | "y";
    /**
     * The minimum and maximum values along the `directionalAxis` at which
     * this function should be graphed. Values of -Infinity and Infinity are
     * allowed. Note that infinite values are serialized as `null` in JSON.
     */
    domain: [min: number, max: number];
    labels: LockedLabelType[];
    ariaLabel?: string;
};

// Not associated with a specific figure
export type LockedLabelType = {
    type: "label";
    coord: Coord;
    /** TeX-supported string */
    text: string;
    color: LockedFigureColor;
    size: "small" | "medium" | "large";
};

export type PerseusGraphType =
    | PerseusGraphTypeAbsoluteValue
    | PerseusGraphTypeAngle
    | PerseusGraphTypeCircle
    | PerseusGraphTypeLinear
    | PerseusGraphTypeLinearSystem
    | PerseusGraphTypeNone
    | PerseusGraphTypePoint
    | PerseusGraphTypePolygon
    | PerseusGraphTypeQuadratic
    | PerseusGraphTypeRay
    | PerseusGraphTypeSegment
    | PerseusGraphTypeSinusoid
    | PerseusGraphTypeExponential
    | PerseusGraphTypeTangent
    | PerseusGraphTypeLogarithm
    | PerseusGraphTypeVector;

export type PerseusGraphTypeAngle = {
    type: "angle";
    /** Whether to show the angle measurements. default: false */
    showAngles?: boolean;
    /** Allow Reflex Angles if an "angle" type. default: true */
    allowReflexAngles?: boolean;
    /** The angle offset in degrees if an "angle" type. default: 0 */
    angleOffsetDeg?: number | null;
    /** Snap to degree increments if an "angle" type. default: 1 */
    snapDegrees?: number;
    /** How to match the answer. If missing, defaults to exact matching. */
    match?: "congruent";
    /**
     * The angle represented as ∠ABC; point B is the vertex, while rays
     * BA and BC are the sides of the angle.
     */
    coords?: [Coord, Coord, Coord];
    /**
     * The initial state for this graph, represented as ∠ABC, where point B is
     * the vertex, while rays BA and BC form the angle.
     */
    startCoords?: [Coord, Coord, Coord];
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: [string, string, string];
};

export type PerseusGraphTypeCircle = {
    type: "circle";
    center?: Coord;
    radius?: number;
    /** The initial coordinates the graph renders with. */
    startCoords?: {
        center: Coord;
        radius: number;
    };
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: string[];
};

export type PerseusGraphTypeLinear = {
    type: "linear";
    /** expects 2 coords */
    coords?: CollinearTuple | null;
    /** The initial coordinates the graph renders with. */
    startCoords?: CollinearTuple;
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: [string, string];
};

export type PerseusGraphTypeLinearSystem = {
    type: "linear-system";
    /** expects 2 sets of 2 coords */
    coords?: CollinearTuple[] | null;
    /** The initial coordinates the graph renders with. */
    startCoords?: CollinearTuple[];
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: string[];
};

export type PerseusGraphTypeNone = {
    type: "none";
};

export type PerseusGraphTypePoint = {
    type: "point";
    /**
     * The number of points if a "point" type. default: 1. "unlimited" if no
     * limit
     */
    numPoints?: number | "unlimited";
    coords?: Coord[] | null;
    /** The initial coordinates the graph renders with. */
    startCoords?: Coord[];
    /** Used instead of `coords` in some old graphs that have only one point. */
    coord?: Coord;
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: string[];
};

export type PerseusGraphTypePolygon = {
    type: "polygon";
    /** The number of sides. default: 3. "unlimited" if no limit */
    numSides?: number | "unlimited";
    /** Whether to show the angle measurements. default: false */
    showAngles?: boolean;
    /** Whether to show side measurements. default: false */
    showSides?: boolean;
    /** How to snap points. e.g. "grid", "angles", or "sides". default: grid */
    snapTo?: "grid" | "angles" | "sides";
    /** How to match the answer. If missing, defaults to exact matching. */
    match?: "similar" | "congruent" | "approx" | "exact";
    coords?: Coord[] | null;
    /** The initial coordinates the graph renders with. */
    startCoords?: Coord[];
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: string[];
};

export type PerseusGraphTypeQuadratic = {
    type: "quadratic";
    /** expects a list of 3 coords */
    coords?: [Coord, Coord, Coord] | null;
    /** The initial coordinates the graph renders with. */
    startCoords?: [Coord, Coord, Coord];
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: [string, string, string];
};

export type PerseusGraphTypeSegment = {
    type: "segment";
    /** The number of segments if a "segment" type. default: 1. Max: 6 */
    numSegments?: number;
    /**
     * Expects a list of Coord tuples. Length should match the `numSegments`
     * value.
     */
    coords?: CollinearTuple[] | null;
    /** The initial coordinates the graph renders with. */
    startCoords?: CollinearTuple[];
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: string[];
};

export type PerseusGraphTypeSinusoid = {
    type: "sinusoid";
    /** Expects a list of 2 Coords */
    coords?: Coord[] | null;
    /** The initial coordinates the graph renders with. */
    startCoords?: Coord[];
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: string[];
};

export type PerseusGraphTypeTangent = {
    type: "tangent";
    // Expects a list of 2 Coords
    coords?: Coord[] | null;
    // The initial coordinates the graph renders with.
    startCoords?: Coord[];
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: string[];
};

export type PerseusGraphTypeExponential = {
    type: "exponential";
    /** Two points along the exponential curve. */
    coords?: Coord[] | null;
    /**
     * The y-value of the horizontal asymptote (the line y = asymptote).
     * Corresponds to the coefficient c in f(x) = a·eᵇˣ + c.
     */
    asymptote?: number | null;
    /** The initial coordinates the graph renders with. */
    startCoords?: {coords: [Coord, Coord]; asymptote: number};
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: string[];
};

export type PerseusGraphTypeLogarithm = {
    type: "logarithm";
    /** Two points along the logarithmic curve. */
    coords?: Coord[] | null;
    /**
     * The x-value of the vertical asymptote (the line x = asymptote).
     * The curve is defined on only one side of this line.
     */
    asymptote?: number | null;
    /** The initial coordinates the graph renders with. */
    startCoords?: {coords: [Coord, Coord]; asymptote: number};
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: string[];
};

export type PerseusGraphTypeAbsoluteValue = {
    type: "absolute-value";
    // Expects [vertex, secondPoint]
    coords?: [Coord, Coord] | null;
    // The initial coordinates the graph renders with.
    startCoords?: [Coord, Coord];
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: [string, string];
};

export type PerseusGraphTypeRay = {
    type: "ray";
    /** Expects a list of 2 Coords */
    coords?: CollinearTuple | null;
    /** The initial coordinates the graph renders with. */
    startCoords?: CollinearTuple;
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: [string, string];
};

export type PerseusGraphTypeVector = {
    type: "vector";
    /** The tail and tip coordinates of the vector: [tail, tip] */
    coords?: CollinearTuple | null;
    /** The initial coordinates the graph renders with. */
    startCoords?: CollinearTuple;
    /** How to match the answer.
     *  "exact" (default) — both tail and tip must match exactly.
     *  "congruent" — same direction and magnitude, any position. */
    match?: "exact" | "congruent";
    /** Custom label for each interactive point that will help with the screen reader. */
    pointLabels?: [string, string];
};

type AbsoluteValueGraphCorrect = {
